<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, sans-serif; background: #f4f6f8; color: #222; padding: 20px; max-width: 800px; margin: 0 auto; }
  h1 { text-align: center; margin-bottom: 20px; }
  h2 { margin: 18px 0 8px; font-size: 1.1rem; }
  section { background: #fff; border-radius: 8px; padding: 16px; margin-bottom: 16px; box-shadow: 0 1px 3px rgba(0,0,0,.1); }
  label { display: block; font-weight: 600; margin: 8px 0 3px; font-size: .9rem; }
  input, select, textarea { width: 100%; padding: 8px; border: 1px solid #ccc; border-radius: 4px; font-size: .95rem; }
  input:focus, select:focus, textarea:focus { outline: none; border-color: #4a90d9; }
  button { cursor: pointer; padding: 9px 18px; border: none; border-radius: 4px; font-size: .95rem; }
  #add-expense { background: #4a90d9; color: #fff; width: 100%; margin-top: 10px; }
  #add-expense:hover { background: #3a7bc8; }
  .exp-del { background: #d9534f; color: #fff; padding: 4px 10px; font-size: .85rem; }
  .exp-del:hover { background: #c9302c; }
  #form-error { color: #d9534f; font-size: .9rem; min-height: 1.2em; margin-top: 6px; }
  table { width: 100%; border-collapse: collapse; margin-top: 6px; }
  th, td { text-align: left; padding: 8px 6px; border-bottom: 1px solid #e8e8e8; font-size: .9rem; }
  th { background: #f0f0f0; font-weight: 600; }
  .expense td.amount { font-weight: 700; }
  .expense.hidden { display: none; }
  #total { font-size: 1.2rem; font-weight: 700; }
  .cat-total { display: inline-block; background: #eef3fa; border-radius: 4px; padding: 4px 10px; margin: 3px 4px 3px 0; font-size: .9rem; }
  .filters-row { display: flex; gap: 10px; flex-wrap: wrap; }
  .filters-row > div { flex: 1; min-width: 140px; }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<section>
  <h2>Add Expense</h2>
  <form id="expense-form" novalidate>
    <label for="amount">Amount</label>
    <input type="number" id="amount" step="0.01" placeholder="0.00">

    <label for="category">Category</label>
    <select id="category">
      <option value="groceries">groceries</option>
      <option value="transport">transport</option>
      <option value="bills">bills</option>
      <option value="fun">fun</option>
    </select>

    <label for="date">Date</label>
    <input type="date" id="date">

    <label for="note">Note (optional)</label>
    <input type="text" id="note" placeholder="e.g. Weekly groceries">

    <div id="form-error"></div>
    <button type="submit" id="add-expense">Add Expense</button>
  </form>
</section>

<!-- Filters -->
<section>
  <h2>Filters</h2>
  <div class="filters-row">
    <div>
      <label for="filter-category">Category</label>
      <select id="filter-category">
        <option value="all">all</option>
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div>
      <label for="filter-from">From</label>
      <input type="date" id="filter-from">
    </div>
    <div>
      <label for="filter-to">To</label>
      <input type="date" id="filter-to">
    </div>
  </div>
</section>

<!-- Summary -->
<section>
  <h2>Summary</h2>
  <p>Total: <span id="total">0.00</span></p>
  <div id="category-totals" style="margin-top:8px;"></div>
</section>

<!-- Expense List -->
<section>
  <h2>Expenses</h2>
  <table>
    <thead>
      <tr>
        <th>Amount</th>
        <th>Category</th>
        <th>Date</th>
        <th>Note</th>
        <th></th>
      </tr>
    </thead>
    <tbody id="expense-list"></tbody>
  </table>
</section>

<script>
(function() {
  const STORAGE_KEY = 'expense_tracker_data';
  let expenses = [];

  // DOM refs
  const form = document.getElementById('expense-form');
  const amountInput = document.getElementById('amount');
  const categoryInput = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const formError = document.getElementById('form-error');
  const expenseList = document.getElementById('expense-list');
  const totalEl = document.getElementById('total');
  const catTotalsEl = document.getElementById('category-totals');
  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');

  // Load from localStorage
  function loadExpenses() {
    try {
      const data = localStorage.getItem(STORAGE_KEY);
      if (data) expenses = JSON.parse(data);
    } catch(e) {
      expenses = [];
    }
  }

  // Save to localStorage
  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // Validation
  function validate() {
    const rawAmount = amountInput.value.trim();
    const rawDate = dateInput.value.trim();

    if (!rawDate) {
      formError.textContent = 'Please select a date.';
      return false;
    }

    if (rawAmount === '' || isNaN(Number(rawAmount))) {
      formError.textContent = 'Please enter a valid numeric amount.';
      return false;
    }

    const num = parseFloat(rawAmount);
    if (num <= 0) {
      formError.textContent = 'Amount must be greater than zero.';
      return false;
    }

    return true;
  }

  // Add expense
  form.addEventListener('submit', function(e) {
    e.preventDefault();
    formError.textContent = '';

    if (!validate()) return;

    const expense = {
      id: Date.now() + Math.random(),
      amount: parseFloat(parseFloat(amountInput.value).toFixed(2)),
      category: categoryInput.value,
      date: dateInput.value,
      note: noteInput.value.trim()
    };

    expenses.push(expense);
    saveExpenses();
    amountInput.value = '';
    noteInput.value = '';
    render();
  });

  // Check if expense matches filters
  function matchesFilters(exp) {
    const cat = filterCategory.value;
    const from = filterFrom.value;
    const to = filterTo.value;

    if (cat !== 'all' && exp.category !== cat) return false;
    if (from && exp.date < from) return false;
    if (to && exp.date > to) return false;
    return true;
  }

  // Render everything
  function render() {
    // Sort newest first
    const sorted = expenses.slice().sort(function(a, b) {
      if (b.date !== a.date) return b.date.localeCompare(a.date);
      return b.id - a.id;
    });

    // Build rows
    expenseList.innerHTML = '';
    let visibleTotal = 0;
    const catSums = {};

    sorted.forEach(function(exp) {
      const tr = document.createElement('tr');
      tr.className = 'expense';
      tr.dataset.id = exp.id;

      if (!matchesFilters(exp)) {
        tr.classList.add('hidden');
      } else {
        visibleTotal += exp.amount;
        catSums[exp.category] = (catSums[exp.category] || 0) + exp.amount;
      }

      const tdAmount = document.createElement('td');
      tdAmount.className = 'amount';
      tdAmount.textContent = exp.amount.toFixed(2);

      const tdCat = document.createElement('td');
      tdCat.textContent = exp.category;

      const tdDate = document.createElement('td');
      tdDate.textContent = exp.date;

      const tdNote = document.createElement('td');
      tdNote.textContent = exp.note || '';

      const tdDel = document.createElement('td');
      const delBtn = document.createElement('button');
      delBtn.className = 'exp-del';
      delBtn.textContent = 'Delete';
      delBtn.addEventListener('click', function() {
        expenses = expenses.filter(function(e) { return e.id !== exp.id; });
        saveExpenses();
        render();
      });
      tdDel.appendChild(delBtn);

      tr.appendChild(tdAmount);
      tr.appendChild(tdCat);
      tr.appendChild(tdDate);
      tr.appendChild(tdNote);
      tr.appendChild(tdDel);
      expenseList.appendChild(tr);
    });

    // Update total
    totalEl.textContent = visibleTotal.toFixed(2);

    // Update category totals
    catTotalsEl.innerHTML = '';
    const allCats = ['groceries', 'transport', 'bills', 'fun'];
    allCats.forEach(function(cat) {
      const span = document.createElement('span');
      span.className = 'cat-total';
      span.setAttribute('data-cat', cat);
      span.textContent = cat + ': ' + (catSums[cat] ? catSums[cat].toFixed(2) : '0.00');
      catTotalsEl.appendChild(span);
    });
  }

  // Filter change listeners
  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  // Init
  loadExpenses();
  render();
})();
</script>

</body>
</html>
